      Future<void> _search(String q) async {
        final r = await dio.get('/search', queryParameters: {'q': q}, cancelToken: _cancel);
        // ...
      }
      @override
      void dispose() {
        _cancel.cancel('page disposed');
        super.dispose();
      }
    }
    ```

